mapper.select:
SELECT c.id, c.user_id, c.product_id, c.quantity, c.created_at, c.updated_at, p.name AS product_name, p.image_url AS product_image_url, p.price AS product_price, p.category AS product_category, p.stock, p.status, (p.price * c.quantity) AS subtotal FROM cart c JOIN product p ON c.product_id = p.id WHERE c.id IN
#{id}
ORDER BY c.created_at DESC
